  ('aboriginal-c5fb3965-moex-00008', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '有關現行原住民身分得喪變更相關規範，下列描述何者為錯誤？', '["泰雅族原住民某甲被排灣族收養，某甲可以申請變更民族別為排灣族", "某乙被非原住民收養並改從養父之姓後，其生父才取得原住民身分，某乙此時可申請改從生父之姓 並取得原住民身分", "原住民某丙成年後申請放棄原住民身分，可以再申請回復原住民身分", "原住民某丁被非原住民養父收養，並且改從養父之姓，某丁會喪失原住民身分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00009', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '現行法律對原住民族政治參與之保障機制，下列描述何者錯誤？', '["政府應依民族意願推動原住民族自治", "鄉（鎮、市）有原住民人口在1千5百人以上者，於該鄉(鎮、市)民代表總額內應有原住民選出之 鄉（鎮、市）民代表名額", "山地鄉鄉長及直轄市山地原住民區區長，應以山地原住民為限", "村（里）長事務補助費每月新臺幣5萬元，於原住民族地區之村（里）每月再增加百分之二十"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00010', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '有關保障原住民族司法權益事項，下列敘述何者錯誤？', '["政府為保障原住民族之司法權益，得設置原住民族法院或法庭", "設立原住民族專庭的地方包括苗栗", "一造當事人為原住民之「確認土地或房屋所有權存在或不存在」民事事件，由原住民族專業法庭（股） 審理", "原告為原住民之刑事案件，不論何種犯罪類型，均由原住民族專業法庭（股）審理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00011', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '司法院釋字第803號解釋認為，民國104年通過之原住民族基於傳統文化及祭儀需要獵捕宰殺利用野 生動物管理辦法第4條第3項規定，有關非定期性獵捕活動所定之申請期限與程序規定部分，其中就 突發性未可事先預期者，欠缺合理彈性，對原住民從事狩獵活動之文化權利所為限制已屬過度，於此 範圍內，因有違憲法何種原則，應自本解釋公布之日起不再適用？', '["自由原則", "平等原則", "比例原則", "法安定性原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00012', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民族基本法，成立財團法人原住民族文化事業基金會，經營原住民族廣播電台，係為保障原 住民族下列何種權益？', '["廣播自由", "媒體近用權", "工作權", "參政權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00013', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '甲學校網頁上關於學校介紹謂「本校發展以泰雅族文化為主之民族實驗教育，強化教師教學與課程設 計等能力，以提昇學生基本能力以及研究探討、解決問題的優勢學習能力。促進原住民族教育之主體 發展，培育具有強烈族群認同的新世代原住民，經X縣實驗教育審議委員會審議通過實施。」甲校最 可能是以下何種學校類型？', '["原住民實驗教育學校", "原住民重點學校", "原住民族學校", "原住民部落學校"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00014', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '花蓮縣萬榮鄉衛生所的標示牌上，除有該衛生所中文標示外，另併呈地方通行語之標示。本項作法乃 係下列何一法律之規定？', '["原住民族基本法", "原住民族教育法", "原住民族語言發展法", "原住民族傳統智慧創作保護條例"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
