  ('aboriginal-c5fb3965-moex-00016', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民保留地禁伐補償條例，下列何種原住民保留地非屬由主管機關劃定為禁伐區域並公告之 條件？', '["依法編定為林業用地或適用林業用地管制", "依法劃設為保護區或水源特定區", "依法劃設為耕地之區域", "依法劃設為國家公園之區域"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00017', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據諮商取得原住民族部落同意參與辦法，部落會議就公共事項之議案欲通過決議，如部落章程未有 特別規定時，應經下列何種程序？', '["由出席之部落成員過半數贊成", "由出席之部落成員三分之二以上贊成", "由部落成員半數以上出席，以及過半數贊成", "由部落成員半數以上出席，以及三分之二以上贊成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "826d2e06d926", "answer_pdf_sha1": "a69f55b1a3ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
